"""AgentRunner — 에이전트 노드.

ToolRegistry로 도구 호출, GraphToolManager로 도구 검색,
ToolGenerator로 런타임 도구 생성. Generator→Buffer 변환 + 이벤트 추출.
"""

from __future__ import annotations

import asyncio
import inspect
import logging
from typing import Any

from mantis.runtime.stream_manager import BufferedFactory

logger = logging.getLogger(__name__)


class AgentRunner:
    async def run(self, node: Any, inputs: dict[str, Any], ctx: Any) -> dict[str, Any]:
        # ─── 1. 노드 실행 (xgen node_class.execute) ───
        instance = node.node_class() if node.node_class else None

        if instance is not None:
            if inspect.iscoroutinefunction(getattr(instance, "execute", None)):
                result = await instance.execute(**inputs)
            elif hasattr(instance, "execute"):
                result = await asyncio.get_event_loop().run_in_executor(
                    None, lambda: instance.execute(**inputs),
                )
            else:
                result = await self._run_mantis_agent(node, inputs, ctx)
        else:
            # node_class 없으면 mantis 에이전트 모드로 실행
            result = await self._run_mantis_agent(node, inputs, ctx)

        # ─── 2. Generator → Buffer + 이벤트 추출 ───
        if inspect.isgenerator(result) or (
            hasattr(result, "__iter__") and hasattr(result, "__next__")
            and not isinstance(result, (str, bytes, dict, list))
        ):
            return self._process_generator(node, result, ctx)

        if isinstance(result, str):
            return {"result": result}
        if isinstance(result, dict):
            return result
        return {"result": result}

    async def _run_mantis_agent(
        self, node: Any, inputs: dict[str, Any], ctx: Any,
    ) -> Any:
        """mantis 내장 에이전트 루프 — PipelineExecutor 사용.

        ctx에 model + tool_registry가 있으면 에이전트 모드로 실행.
        search가 있으면 도구 검색 활성화.
        sandbox가 있으면 create_tool/execute_code 활성화.
        """
        model = ctx.model if hasattr(ctx, "model") else None
        if model is None:
            return {"result": inputs.get("text", "")}

        try:
            from mantis.executor.pipeline import PipelineExecutor
            from mantis.context.conversation import ConversationContext

            # PipelineExecutor 생성 (providers 전부 전달)
            executor = PipelineExecutor(
                model=model,
                tools=ctx.tool_registry if hasattr(ctx, "tool_registry") else None,
                search=ctx.search if hasattr(ctx, "search") else None,
                sandbox=ctx.sandbox if hasattr(ctx, "sandbox") else None,
                workflows=ctx.workflows if hasattr(ctx, "workflows") else None,
                state=ctx.state if hasattr(ctx, "state") else None,
                system_prompt=inputs.get("system_prompt", node.parameters.get("system_prompt", "")),
            )

            prompt = inputs.get("text", inputs.get("input", ""))
            if not prompt:
                prompt = str(next(iter(inputs.values()), ""))

            # 에이전트 실행 + 중간 이벤트 전파
            result_text = ""
            async for event in executor.run_stream(str(prompt)):
                etype = event.get("type", "")
                if etype == "done":
                    result_text = event.get("data", "")
                elif etype == "tool_call":
                    ctx.emit({
                        "type": "agent_tool_call",
                        "data": {"node_id": node.id, **event.get("data", {})},
                    })
                elif etype == "tool_result":
                    ctx.emit({
                        "type": "agent_tool_result",
                        "data": {"node_id": node.id, **event.get("data", {})},
                    })
                elif etype == "thinking":
                    ctx.emit({
                        "type": "stream_chunk",
                        "data": {"node_id": node.id, "chunk": f"[thinking iter {event['data']['iteration']}]"},
                    })

            return {"result": result_text}

        except ImportError:
            logger.warning("PipelineExecutor를 import할 수 없어 에이전트 실행 불가")
            return {"result": inputs.get("text", "")}

    def _process_generator(
        self, node: Any, result: Any, ctx: Any,
    ) -> dict[str, Any]:
        """Generator → BufferedFactory 변환 + 이벤트 추출."""
        chunks = []
        text_chunks = []

        for chunk in result:
            chunks.append(chunk)
            if isinstance(chunk, dict) and chunk.get("type") == "agent_event":
                ctx.emit({"type": "agent_tool_call", "data": {"node_id": node.id, **chunk}})
            elif isinstance(chunk, str):
                text_chunks.append(chunk)
                ctx.emit({"type": "stream_chunk", "data": {"node_id": node.id, "chunk": chunk}})

        factory = BufferedFactory(chunks)
        streaming_port = next((p.id for p in node.outputs if "stream" in p.id.lower()), None)
        result_port = next((p.id for p in node.outputs if "result" in p.id.lower()), None)

        output: dict[str, Any] = {}
        if streaming_port:
            output[streaming_port] = factory
        if result_port:
            output[result_port] = "".join(text_chunks)
        if not output:
            output["result"] = "".join(text_chunks) if text_chunks else factory

        return output
